substitutions:
  device_version: "0.9"

esphome:
  name: openshrooly
  name_add_mac_suffix: true
  friendly_name: OpenShrooly
  project:
    name: grahamsz.openshrooly
    version: ${device_version}
  platformio_options:
    build_flags:
      - -Wno-cpp  # Suppress preprocessor warnings (including deprecation warnings)

  on_boot:
    priority: 600  # Very early boot
    then:
      # Start SWD programming immediately
      - lambda: |-
          ESP_LOGI("boot", "Starting SWD programming early...");
      - swd_programmer.program: swd

      # Wait 3 seconds for SWD to get going, then LVGL will initialize
      - delay: 3s

      - lambda: |-
          ESP_LOGI("boot", "LVGL should initialize now with main page...");

      # Force main page to show after LVGL initializes
      - delay: 200ms
      - lambda: |-
          ESP_LOGI("boot", "Forcing main page display...");
      - lvgl.page.show: aaaa
      - delay: 100ms  # Small delay between page show and update
      - component.update: my_display

      # Wait for SWD programming to complete (typically takes 5-7 seconds total)
      - delay: 5s
      - lambda: |-
          ESP_LOGI("boot", "SWD programming should be complete, starting fan control...");

      # Continue with normal boot sequence
      - script.stop: fan_rpm_check
      - script.stop: fan_stop_check
      - script.execute: air_exchange_manager
      - script.execute: touch_button_monitor

      # Restart WiFi AP after 5 seconds to ensure DHCP server is running
      - delay: 5s
      - script.execute: wifi_ap_bounce
      - script.wait: wifi_ap_bounce
      - delay: 4s
      - script.execute: wifi_ap_boot_verify
      - script.execute: ensure_device_name

      # Wait until humidity is valid
      - wait_until:
          condition:
            lambda: 'return !isnan(id(humidity).state);'
          timeout: 30s

      # Start humidity control
      - lambda: |-
          ESP_LOGI("boot", "🌊 Humidity sensor ready, starting humidity control manager");
      - script.execute: humidity_control_manager

esp32:
  board: esp32-s3-devkitc-1
  variant: esp32s3
  framework:
    type: arduino

logger:
  level: INFO


api:
  reboot_timeout: 0s

ota:
  platform: esphome


external_components:
  - source:
      type: local
      path: external_components
# LVGL is now a native component in ESPHome 2024.8.0+

wifi:
  ap:
    ssid: "OpenShrooly"
    manual_ip:
      static_ip: 192.168.4.1
      gateway: 192.168.4.1
      subnet: 255.255.255.0

  on_connect:
    then:
      - component.update: my_display

  on_disconnect:
    then:
      - script.execute: wifi_ap_bounce

captive_portal:

# Include text sensors early so scripts can reference them
<<: !include components/text_sensors.yaml
<<: !include components/texts.yaml

# Scripts will be loaded after components to ensure all IDs are available

interval:
  # Water level check interval (every 30 seconds)
  - interval: 1s
    then:
      - script.execute: lighting_control_manager

  - interval: 60s
    then:
      - lambda: |-
          auto t = id(sntp_time).now();
          if (t.is_valid()) {
            ESP_LOGI("time",
              "Local time: %04d-%02d-%02d %02d:%02d:%02d",
              t.year, t.month, t.day_of_month,
              t.hour, t.minute, t.second
            );
          } else {
            ESP_LOGW("time", "SNTP time not valid yet");
          }


  - interval: 30s # Every 30 seconds, run the water level calculator
    then:
      - script.execute: water_level_calculator          

  # Watchdog: nudge SoftAP/DHCP if the STA link stays down
  - interval: 45s
    then:
      - lambda: |-
          const uint32_t now = millis();

          if (WiFi.isConnected()) {
            return;
          }

          if (id(ap_restart_in_progress)) {
            ESP_LOGD("wifi", "AP restart in progress; watchdog skipping.");
            return;
          }

          IPAddress ap_ip = WiFi.softAPIP();
          const uint32_t elapsed = now - id(ap_last_restart_ms);
          const bool ip_expected = (ap_ip[0] == 192 && ap_ip[1] == 168 && ap_ip[2] == 4 && ap_ip[3] == 1);

          if (ip_expected) {
            return;
          }

          if (elapsed < 30000) {
            ESP_LOGI(
              "wifi",
              "SoftAP IP %u.%u.%u.%u seen %ums after last restart; waiting before retry.",
              static_cast<unsigned int>(ap_ip[0]),
              static_cast<unsigned int>(ap_ip[1]),
              static_cast<unsigned int>(ap_ip[2]),
              static_cast<unsigned int>(ap_ip[3]),
              static_cast<unsigned int>(elapsed)
            );
            return;
          }

          ESP_LOGW(
            "wifi",
            "SoftAP IP unhealthy (%u.%u.%u.%u); re-running restart helper.",
            static_cast<unsigned int>(ap_ip[0]),
            static_cast<unsigned int>(ap_ip[1]),
            static_cast<unsigned int>(ap_ip[2]),
            static_cast<unsigned int>(ap_ip[3])
          );

          id(wifi_ap_bounce).execute();

  # Update LVGL labels every 10 seconds
  - interval: 10s
    then:
      # Update main screen value labels
      - lvgl.label.update:
          id: main_temp_value
          text: !lambda |-
            if (id(temperature).has_state()) {
              char str[20];
              sprintf(str, "%.1f°C", id(temperature).state);
              return std::string(str);
            }
            return std::string("--.-°C");

      - lvgl.label.update:
          id: main_humidity_value
          text: !lambda |-
            if (id(humidity).has_state()) {
              char str[20];
              sprintf(str, "%.1f%%", id(humidity).state);
              return std::string(str);
            }
            return std::string("--.-%");

      - lvgl.label.update:
          id: main_water_value
          text: !lambda |-
            if (id(water_level_percent).has_state()) {
              char str[20];
              sprintf(str, "%.0f%%", id(water_level_percent).state);
              return std::string(str);
            }
            return std::string("---%");

      - lvgl.label.update:
          id: main_fan_value
          text: !lambda |-
            if (id(air_exchange_on_flag)) {
              return std::string("ON");
            } else {
              return std::string("OFF");
            }

      - lvgl.label.update:
          id: main_light_value
          text: !lambda |-
            if (id(lights_on_flag)) {
              char str[20];
              sprintf(str, "%.0f lux", id(white_intensity).state);
              return std::string(str);
            } else {
              return std::string("OFF");
            }

      - lvgl.label.update:
          id: main_wifi_value
          text: !lambda |-
            if (id(ap_restart_in_progress)) {
              return std::string("Restarting AP...");
            }

            if (WiFi.isConnected()) {
              return std::string("Connected");
            }

            return std::string("AP Mode");

      - lvgl.label.update:
          id: main_ip_value
          text: !lambda |-
            if (id(ap_restart_in_progress)) {
              return std::string("--.--.--.--");
            }

            if (WiFi.isConnected()) {
              return WiFi.localIP().toString().c_str();
            }

            return std::string("192.168.4.1");

      - lvgl.label.update:
          id: main_time_label
          text: !lambda |-
            auto time = id(sntp_time).now();
            if (time.is_valid()) {
              char str[10];
              sprintf(str, "%02d:%02d", time.hour, time.minute);
              return std::string(str);
            }
            return std::string("00:00");

      - lvgl.label.update:
          id: main_uptime_value
          text: !lambda |-
            uint32_t uptime_sec = millis() / 1000;
            uint32_t hours = uptime_sec / 3600;
            uint32_t minutes = (uptime_sec % 3600) / 60;
            char str[20];
            sprintf(str, "%dh %dm", hours, minutes);
            return std::string(str);

      - lvgl.label.update:
          id: main_status_message
          text: !lambda |-
            return id(ap_status_text).c_str();

      # Force display update
      - component.update: my_display


